Here's the complete setup:

**Program.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;
using OpenTelemetry.Metrics;
using OpenTelemetry.Resources;
using OpenTelemetry.Trace;

var builder = WebApplication.CreateBuilder(args);

var serviceName = "OrderApi";
var serviceVersion = "1.0.0";

builder.Services.AddOpenTelemetry()
    .ConfigureResource(r => r.AddService(
        serviceName: serviceName,
        serviceVersion: serviceVersion))
    .WithTracing(tracing => tracing
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddSource(OrderService.ActivitySourceName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }))
    .WithMetrics(metrics => metrics
        .AddAspNetCoreInstrumentation()
        .AddMeter(OrderService.MeterName)
        .AddOtlpExporter(opts =>
        {
            opts.Endpoint = new Uri("http://localhost:4317");
        }));

builder.Services.AddSingleton<OrderService>();
builder.Services.AddControllers();

var app = builder.Build();
app.MapControllers();
app.Run();
```

**OrderService.cs**

```csharp
using System.Diagnostics;
using System.Diagnostics.Metrics;

public class OrderService
{
    public const string ActivitySourceName = "OrderApi.OrderService";
    public const string MeterName = "OrderApi.OrderService";

    private static readonly ActivitySource ActivitySource = new(ActivitySourceName);
    private static readonly Meter Meter = new(MeterName);
    private static readonly Counter<long> OrdersProcessed = Meter.CreateCounter<long>(
        "orders.processed",
        unit: "{order}",
        description: "Number of orders processed");

    public async Task<OrderResult> ProcessOrder(Order order)
    {
        using var activity = ActivitySource.StartActivity("ProcessOrder", ActivityKind.Internal);
        activity?.SetTag("order.id", order.Id);
        activity?.SetTag("order.total", order.Total);

        try
        {
            // Your processing logic here
            await Task.Delay(100); // simulate work

            activity?.SetStatus(ActivityStatusCode.Ok);
            OrdersProcessed.Add(1, new KeyValuePair<string, object?>("order.status", "success"));

            return new OrderResult { Success = true };
        }
        catch (Exception ex)
        {
            activity?.SetStatus(ActivityStatusCode.Error, ex.Message);
            activity?.RecordException(ex);
            OrdersProcessed.Add(1, new KeyValuePair<string, object?>("order.status", "failure"));
            throw;
        }
    }
}

public record Order { public string Id { get; init; } = ""; public decimal Total { get; init; } }
public record OrderResult { public bool Success { get; init; } }
```

**Required packages:**

```xml
<PackageReference Include="OpenTelemetry.AspNetCore" Version="1.9.*" />
<PackageReference Include="OpenTelemetry.Exporter.OpenTelemetryProtocol" Version="1.9.*" />
<PackageReference Include="OpenTelemetry.Extensions.Hosting" Version="1.9.*" />
<PackageReference Include="OpenTelemetry.Instrumentation.AspNetCore" Version="1.9.*" />
<PackageReference Include="OpenTelemetry.Instrumentation.Http" Version="1.9.*" />
```

**Key points:**

- `ActivitySource` is .NET's API for creating spans — `StartActivity` begins a new span.
- The custom counter uses `System.Diagnostics.Metrics`, which OTel's SDK bridges to OTLP.
- `AddSource(...)` and `AddMeter(...)` register your custom instrumentation with the SDK so it gets exported.
- The OTLP exporter defaults to gRPC on port 4317. Set `OTEL_EXPORTER_OTLP_ENDPOINT` env var to override.
